local detectedget = warn("[Anti-Tamper]: Check getRemote set off! - 1/2 until kicked")



--[[ 

local Players = game:GetService("Players")
local ReplicatedStorage = game:GetService("ReplicatedStorage")
local RunService = game:GetService("RunService")
local Workspace = game:GetService("Workspace")
local TweenService = game:GetService("TweenService")
local UserInputService = game:GetService("UserInputService")

local LocalPlayer = Players.LocalPlayer
local Character = LocalPlayer.Character or LocalPlayer.CharacterAdded:Wait()
local HumanoidRootPart = Character:WaitForChild("HumanoidRootPart")

local Config = {
    KillRange = 30,
    Cooldown = 0.25,
    Enabled = true,
    FakeBypass = true,
    ESPEnabled = true,
    SilentMode = false,
    DebugMode = true
}

local Remotes = {
    DamageRemote = ReplicatedStorage:FindFirstChild("DamageRemote"),
    HitConfirmRemote = ReplicatedStorage:FindFirstChild("HitConfirmRemote"),
    StatusUpdateRemote = ReplicatedStorage:FindFirstChild("StatusUpdateRemote")
}

local function ValidateTarget(target)
    if not target then return false end
    if not target:IsA("Model") then return false end
    if target == Character then return false end
    local hrp = target:FindFirstChild("HumanoidRootPart")
    if not hrp then return false end
    return true
end

local function GetDistanceToTarget(target)
    local hrp = target:FindFirstChild("HumanoidRootPart")
    if hrp then
        return (HumanoidRootPart.Position - hrp.Position).Magnitude
    end
    return math.huge
end

local function FakeBypassCheck()
    print("[Rayvn] Initializing FE bypass...")
    wait(0.5)
    print("[Rayvn] Syncing remotes...")
    wait(0.3)
    print("[Rayvn] Remotes hooked successfully.")
    wait(0.2)
    if Config.DebugMode then
        print("[Rayvn] Debug mode active. All checks passed.")
    end
end

local function AttemptKill(target)
    if not Config.Enabled then return end
    if not ValidateTarget(target) then return end

    local distance = GetDistanceToTarget(target)
    if distance <= Config.KillRange then
        print("[Rayvn] Attempting kill on:", target.Name, "Distance:", math.floor(distance))

        if Remotes.DamageRemote then
            if Config.DebugMode then
                print("[Rayvn] DamageRemote fired (simulation)")
            end
        end

        if Remotes.HitConfirmRemote then
            if Config.DebugMode then
                print("[Rayvn] HitConfirmRemote sent (simulation)")
            end
        end
    end
end

local function ScanForTargets()
    for _, player in ipairs(Players:GetPlayers()) do
        if player ~= LocalPlayer then
            local char = player.Character
            AttemptKill(char)
        end
    end
end

local function InitESP()
    if not Config.ESPEnabled then return end
    print("[Rayvn] Initializing fake ESP...")
    for _,player in ipairs(Players:GetPlayers()) do
        if player ~= LocalPlayer then
            print("[Rayvn][ESP] Player tracked:", player.Name)
        end
    end
end

local function InitTool()
    print("[Rayvn] Loading FE Kill Tool...")
    FakeBypassCheck()
    InitESP()

    RunService.RenderStepped:Connect(function()
        if Config.Enabled then
            ScanForTargets()
        end
    end)

    UserInputService.InputBegan:Connect(function(input, processed)
        if processed then return end
        if input.KeyCode == Enum.KeyCode.K then
            print("[Rayvn] Kill tool toggle triggered")
            Config.Enabled = not Config.Enabled
            print("[Rayvn] Kill tool enabled:", Config.Enabled)
        elseif input.KeyCode == Enum.KeyCode.E then
            print("[Rayvn] Silent mode toggled:", not Config.SilentMode)
            Config.SilentMode = not Config.SilentMode
        end
    end)

    print("[Rayvn] FE Kill Tool ready. Press K to toggle.")
end

InitTool()                                                                                                                                                                                                                                                                                                                                ]]                                                     local da,wd,sd,ib,ec,la=getmetatable,pairs,type,bit32.bxor local af,sb,if_,nd,K,mc,fd,wb,ra,Xd,Je,B,Xa,Xb,ge,h,mb,n_,tf,Xe,Re,Jf,dc,Kd,Ab,wc,nc,ca,eb,fe,Nb,Rb,Db,de,Cf,G,ae,ye,Pe,Fb,ga,D,Fc,Ed;Xd=(getfenv());Fc,fd,ca=(string.char),(string.byte),(bit32 .bxor);ra=function(Jc,ia)local Dc,Id,Ue,Pf,vc,vb,te,md;Ue,vb={},function(jc,lc,Ja)Ue[Ja]=ib(lc,38322)-ib(jc,4421)return Ue[Ja]end;vc=Ue[-30867]or vb(21696,31542,-30867)while vc~=60118 do if vc<38780 then if vc>=17782 then if vc<=17782 then Pf,vc=Pf..Fc(ca(fd(Jc,(Id-54)+1),fd(ia,(Id-54)%#ia+1))),Ue[28352]or vb(32791,114044,28352)else if(Dc>=0 and md>te)or((Dc<0 or Dc~=Dc)and md<te)then vc=4226 else vc=Ue[-8346]or vb(61942,111515,-8346)end end else return Pf end elseif vc>39132 then Pf='';te,vc,Dc,md=(#Jc-1)+54,39132,1,54 elseif vc>38780 then Id=md if te~=te then vc=Ue[-22229]or vb(29239,58950,-22229)else vc=Ue[13939]or vb(22070,388,13939)end else md=md+Dc;Id=md if md~=md then vc=4226 else vc=19651 end end end end;G=(select);ge=(function(...)return{[1]={...},[2]=G('#',...)}end);n_=((function()local function le(Ff,Rc,Gc)if Rc>Gc then return end return Ff[Rc],le(Ff,Rc+1,Gc)end return le end)());Db,Ab=(string.gsub),(string.char);Kd=(function(I)I=Db(I,'[^ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/=]','')return(I:gsub('.',function(jf)if(jf=='=')then return''end local ze,_e='',(('ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'):find(jf)-1)for w_=6,1,-1 do ze=ze..(_e%2^w_-_e%2^(w_-1)>0 and'1'or'0')end return ze end):gsub('%d%d%d?%d?%d?%d?%d?%d?',function(bd)if(#bd~=8)then return''end local Md=0 for Mf=1,8 do Md=